/**
 * Formatea un número de cuenta/tarjeta separando cada 4 caracteres con espacio
 * @param {string|number} numero
 * @returns {string}
 */
export const formatoNumeroCuentaTarjeta = (numero) => {
  const numeroLimpio = numero.toString().replace(/^0+/, '')
  return agregarCaracter(numeroLimpio, ' ', 4)
}

/**
 * Ofusca todos los caracteres excepto los últimos 4, usando 'x'
 * @param {string} str
 * @returns {string}
 */
export const ofuscarNumero = (str) => {
  if (str.slice(0, 4) === 'xxxx') return str
  if (/^\d{4} \d{4} \d{4} \d{4}$/.test(str)) return str

  str = str.replace(/^0+/, '')
  let textoOculto = str.slice(0, -4).replace(/./g, 'x') + str.slice(-4)
  let textoFinal = ''
  for (let i = 0; i < textoOculto.length; i++) {
    if (i > 0 && i % 4 === 0) textoFinal += ' '
    textoFinal += textoOculto[i]
  }
  return textoFinal
}

/**
 * Ofusca todos los caracteres excepto los últimos 4, usando '*'
 * @param {string} str
 * @param {boolean} cortado - Si true, muestra solo los últimos 8 dígitos
 * @returns {string}
 */
export const ofuscarNumeroConAsteriscos = (str, cortado = false) => {
  if (str.slice(0, 4) === '****') return str
  str = str.replace(/\s+/g, '')
  let textoOculto = str.slice(0, -4).replace(/./g, '*') + str.slice(-4)
  if (cortado) textoOculto = textoOculto.slice(-8)
  let textoFinal = ''
  for (let i = 0; i < textoOculto.length; i++) {
    if (i > 0 && i % 4 === 0) textoFinal += ' '
    textoFinal += textoOculto[i]
  }
  return textoFinal
}

// Helper interno
const agregarCaracter = (cadena, caracter, pasos) => {
  let resultado = ''
  for (let i = 0; i < cadena.length; i += pasos) {
    if (i + pasos < cadena.length) {
      resultado += cadena.substring(i, i + pasos) + caracter
    } else {
      resultado += cadena.substring(i, cadena.length)
    }
  }
  return resultado
}
